from dataclasses import dataclass, field
from typing import List, Optional, Dict, Tuple
from enum import Enum
import math
import random


class ReplacementPolicy(Enum):
    LRU = "lru"
    RANDOM = "random"


class AccessType(Enum):
    READ = "read"
    WRITE = "write"


class MissType(Enum):
    COMPULSORY = "compulsory"
    CAPACITY = "capacity"
    CONFLICT = "conflict"


@dataclass
class CacheConfig:
    total_size: int
    block_size: int
    associativity: int
    replacement_policy: ReplacementPolicy = ReplacementPolicy.LRU
    address_bits: int = 32
    num_blocks: int = field(init=False)
    num_sets: int = field(init=False)
    offset_bits: int = field(init=False)
    index_bits: int = field(init=False)
    tag_bits: int = field(init=False)

    def __post_init__(self):
        assert self.total_size > 0 and (self.total_size & (self.total_size - 1)) == 0
        assert self.block_size > 0 and (self.block_size & (self.block_size - 1)) == 0
        assert self.total_size >= self.block_size
        self.num_blocks = self.total_size // self.block_size
        assert self.associativity > 0 and self.associativity <= self.num_blocks
        assert self.num_blocks % self.associativity == 0
        self.num_sets = self.num_blocks // self.associativity
        self.offset_bits = int(math.log2(self.block_size))
        self.index_bits = int(math.log2(self.num_sets))
        self.tag_bits = self.address_bits - self.offset_bits - self.index_bits


@dataclass
class CacheLine:
    valid: bool = False
    dirty: bool = False
    tag: int = 0
    lru_counter: int = 0
    data: Optional[bytes] = None


class AddressDecoder:
    def __init__(self, config: CacheConfig):
        self.config = config
        self.offset_mask = (1 << config.offset_bits) - 1
        self.index_mask = (1 << config.index_bits) - 1

    def decode(self, address: int) -> Tuple[int, int, int]:
        offset = address & self.offset_mask
        index = (address >> self.config.offset_bits) & self.index_mask
        tag = address >> (self.config.offset_bits + self.config.index_bits)
        return (tag, index, offset)

    def block_address(self, address: int) -> int:
        return address >> self.config.offset_bits


class CacheSet:
    def __init__(self, associativity: int):
        self.lines: List[CacheLine] = [CacheLine() for _ in range(associativity)]
        self.access_counter: int = 0

    def find_line(self, tag: int) -> Optional[CacheLine]:
        for line in self.lines:
            if line.valid and line.tag == tag:
                return line
        return None

    def find_victim(self, policy: ReplacementPolicy) -> int:
        # Prefer invalid lines first
        for i, line in enumerate(self.lines):
            if not line.valid:
                return i
        if policy == ReplacementPolicy.LRU:
            min_counter = self.lines[0].lru_counter
            min_index = 0
            for i, line in enumerate(self.lines):
                if line.lru_counter < min_counter:
                    min_counter = line.lru_counter
                    min_index = i
            return min_index
        else:  # RANDOM
            return random.randint(0, len(self.lines) - 1)

    def update_lru(self, line_index: int):
        self.access_counter += 1
        self.lines[line_index].lru_counter = self.access_counter


@dataclass
class CacheStats:
    hits: int = 0
    misses: int = 0
    reads: int = 0
    writes: int = 0
    compulsory_misses: int = 0
    capacity_misses: int = 0
    conflict_misses: int = 0
    evictions: int = 0
    dirty_evictions: int = 0

    @property
    def total_accesses(self) -> int:
        return self.hits + self.misses

    @property
    def hit_rate(self) -> float:
        if self.total_accesses == 0:
            return 0.0
        return self.hits / self.total_accesses

    @property
    def miss_rate(self) -> float:
        return 1.0 - self.hit_rate


class Cache:
    def __init__(self, config: CacheConfig):
        self.config = config
        self.decoder = AddressDecoder(config)
        self.sets: List[CacheSet] = [
            CacheSet(config.associativity) for _ in range(config.num_sets)
        ]
        self.stats = CacheStats()
        self.seen_blocks: set = set()
        self._fully_assoc_tags: list = []
        self._fully_assoc_capacity: int = config.num_blocks

    def access(self, address: int, access_type: AccessType = AccessType.READ) -> bool:
        tag, index, offset = self.decoder.decode(address)
        block_addr = self.decoder.block_address(address)
        cache_set = self.sets[index]

        if access_type == AccessType.READ:
            self.stats.reads += 1
        else:
            self.stats.writes += 1

        line = cache_set.find_line(tag)
        if line is not None:
            # HIT
            self.stats.hits += 1
            line_idx = cache_set.lines.index(line)
            cache_set.update_lru(line_idx)
            if access_type == AccessType.WRITE:
                line.dirty = True
            self._update_fully_assoc_tracker(block_addr)
            return True
        else:
            # MISS
            self.stats.misses += 1
            miss_type = self._classify_miss(block_addr)
            if miss_type == MissType.COMPULSORY:
                self.stats.compulsory_misses += 1
            elif miss_type == MissType.CAPACITY:
                self.stats.capacity_misses += 1
            else:
                self.stats.conflict_misses += 1

            self.seen_blocks.add(block_addr)

            victim_idx = cache_set.find_victim(self.config.replacement_policy)
            victim = cache_set.lines[victim_idx]
            if victim.valid:
                self.stats.evictions += 1
                if victim.dirty:
                    self.stats.dirty_evictions += 1

            victim.valid = True
            victim.tag = tag
            victim.dirty = (access_type == AccessType.WRITE)
            cache_set.update_lru(victim_idx)

            self._update_fully_assoc_tracker(block_addr)
            return False

    def _classify_miss(self, block_addr: int) -> MissType:
        if block_addr not in self.seen_blocks:
            return MissType.COMPULSORY
        if block_addr not in self._fully_assoc_tags:
            return MissType.CAPACITY
        return MissType.CONFLICT

    def _update_fully_assoc_tracker(self, block_addr: int):
        if block_addr in self._fully_assoc_tags:
            self._fully_assoc_tags.remove(block_addr)
        elif len(self._fully_assoc_tags) >= self._fully_assoc_capacity:
            self._fully_assoc_tags.pop(0)
        self._fully_assoc_tags.append(block_addr)

    def process_trace(self, trace: List[Dict]) -> CacheStats:
        for entry in trace:
            addr = int(entry["address"], 16)
            atype = AccessType.READ if entry["type"] == "read" else AccessType.WRITE
            self.access(addr, atype)
        return self.stats

    def reset(self):
        self.sets = [
            CacheSet(self.config.associativity)
            for _ in range(self.config.num_sets)
        ]
        self.stats = CacheStats()
        self.seen_blocks.clear()
        self._fully_assoc_tags.clear()
